/* ELEV_FR — grille d'élévation France métropole + Corse, générée depuis le DEM AWS terrarium z9 (~300 m/px).
   Valeur = altitude MAX du terrain dans la maille (0,0125° ≈ 1,2 km), en pieds AMSL. Mer = sentinelle 65535.
   Usage : ELEV_FR_get(lat,lon) → ft (0 si mer) ; ELEV_FR_sea(lat,lon) → true si maille maritime. */
window.ELEV_FR={lat0:41.0,lon0:-5.5,dlat:0.0125,dlon:0.0125,rows:840,cols:1240,unit:'ft',sea:65535,b64:""};
window.ELEV_FR__cell=function(lat,lon){var E=window.ELEV_FR;if(!E)return null;if(!E._u16){try{var b=atob(E.b64),n=b.length,u=new Uint8Array(n);for(var i=0;i<n;i++)u[i]=b.charCodeAt(i);E._u16=new Uint16Array(u.buffer);}catch(e){return null;}}var r=Math.floor((lat-E.lat0)/E.dlat),c=Math.floor((lon-E.lon0)/E.dlon);if(r<0||c<0||r>=E.rows||c>=E.cols)return null;return E._u16[r*E.cols+c];};
window.ELEV_FR_get=function(lat,lon){var v=window.ELEV_FR__cell(lat,lon);if(v==null)return null;return v===65535?0:v;};
window.ELEV_FR_sea=function(lat,lon){var v=window.ELEV_FR__cell(lat,lon);return v===65535;};
